def lcs_length(a, b):
    # compute LCS length at char level
    aa = normalize_ar(a)
    bb = normalize_ar(b)
    n, m = len(aa), len(bb)
    # Use dynamic programming optimized O(min(n,m))
    # But len might be up to 200; okay to use full DP
    dp = [[0]*(m+1) for _ in range(n+1)]
    for i in range(1, n+1):
        ai = aa[i-1]
        for j in range(1, m+1):
            if ai == bb[j-1]:
                dp[i][j] = dp[i-1][j-1] + 1
            else:
                if dp[i-1][j] >= dp[i][j-1]:
                    dp[i][j] = dp[i-1][j]
                else:
                    dp[i][j] = dp[i][j-1]
    return dp[n][m], aa, bb

